mapper.sql:
a.deleted = 0 and a.publish_status = '1' and a.publish_time is not null and a.publish_time <= now() and (a.expire_time is null or a.expire_time > now()) and ( a.scope_type = 'all'
or ( a.scope_type = 'assign' and a.scope_payload is not null and json_contains(a.scope_payload, cast(#{userId} as json), '$') ) or ( a.scope_type = 'role' and a.scope_payload is not null and exists ( select 1 from b_user bu where bu.id = #{userId} and bu.del_flag = '0' and json_contains(a.scope_payload, cast(bu.user_type as json), '$') ) )
)

mapper.select:
select a.id, a.title, cast(a.content as char) as content, a.scope_type, cast(a.scope_payload as char) as scope_payload, a.publish_status, a.publish_time, a.expire_time, a.deleted, a.created_by, a.created_at, a.updated_by, a.updated_at, 0 as is_read from announcement a where a.deleted = 0
and a.title like concat('%', #{title}, '%')
and a.scope_type = #{scopeType}
and a.publish_status = #{publishStatus}
order by a.created_at desc, a.id desc

mapper.update:
update announcement
title = #{title}, content = #{content}, scope_type = #{scopeType}, scope_payload = #{scopePayload}, publish_status = #{publishStatus}, publish_time = #{publishTime}, expire_time = #{expireTime}, deleted = #{deleted}, updated_by = #{updateBy}, updated_at = #{updateTime},
where id = #{id}
